@namespace sv_25e76fdbe5fb4daea2443b67cafef294.Components.Pages.ApplySteps

<div class="step-indicator d-flex justify-content-between mb-4">
    @for (int i = 0; i < StepNames.Length; i++)
    {
        var stepIndex = i;
        var isCompleted = stepIndex < CurrentStep;
        var isCurrent = stepIndex == CurrentStep;
        var isFuture = stepIndex > CurrentStep;

        <div class="step-item text-center flex-fill position-relative @(isCurrent ? "active" : "") @(isCompleted ? "completed" : "") @(isFuture ? "dimmed" : "")"
             @onclick="() => OnStepClick(stepIndex)"
             style="cursor: @(isCompleted ? "pointer" : "default")">

            <div class="step-circle mx-auto mb-1 d-flex align-items-center justify-content-center rounded-circle
                        @(isCurrent ? "bg-primary text-white" : isCompleted ? "bg-success text-white" : "bg-light text-muted border")"
                 style="width: 36px; height: 36px; font-size: 0.85rem;">
                @if (isCompleted)
                {
                    <span>&#10003;</span>
                }
                else
                {
                    <span>@(stepIndex + 1)</span>
                }
            </div>
            <small class="@(isFuture ? "text-muted" : isCurrent ? "fw-bold text-primary" : "text-success")">
                @StepNames[stepIndex]
            </small>
        </div>
    }
</div>

@code {
    private static readonly string[] StepNames =
    {
        "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"
    };

    [Parameter] public int CurrentStep { get; set; }
    [Parameter] public EventCallback<int> OnNavigateToStep { get; set; }

    private async Task OnStepClick(int step)
    {
        if (step < CurrentStep)
        {
            await OnNavigateToStep.InvokeAsync(step);
        }
    }
}

@namespace sv_25e76fdbe5fb4daea2443b67cafef294.Components.Pages.ApplySteps

<h4 class="mb-3">Personal Information</h4>

<div class="mb-3">
    <label class="form-label">Full Name <span class="text-danger">*</span></label>
    <input type="text" class="form-control @(Errors.ContainsKey("FullName") ? "is-invalid" : "")"
           @bind="FullName" @bind:event="oninput" />
    @if (Errors.ContainsKey("FullName"))
    {
        <div class="invalid-feedback">@Errors["FullName"]</div>
    }
</div>

<div class="mb-3">
    <label class="form-label">Email <span class="text-danger">*</span></label>
    <input type="email" class="form-control @(Errors.ContainsKey("Email") ? "is-invalid" : "")"
           @bind="Email" @bind:event="oninput" />
    @if (Errors.ContainsKey("Email"))
    {
        <div class="invalid-feedback">@Errors["Email"]</div>
    }
</div>

<div class="mb-3">
    <label class="form-label">Phone <span class="text-danger">*</span></label>
    <input type="tel" class="form-control @(Errors.ContainsKey("Phone") ? "is-invalid" : "")"
           @bind="Phone" @bind:event="oninput" />
    @if (Errors.ContainsKey("Phone"))
    {
        <div class="invalid-feedback">@Errors["Phone"]</div>
    }
</div>

<div class="mb-3">
    <label class="form-label">Address <span class="text-danger">*</span></label>
    <textarea class="form-control @(Errors.ContainsKey("Address") ? "is-invalid" : "")"
              rows="2" @bind="Address" @bind:event="oninput"></textarea>
    @if (Errors.ContainsKey("Address"))
    {
        <div class="invalid-feedback">@Errors["Address"]</div>
    }
</div>

<div class="d-flex justify-content-end">
    <button class="btn btn-primary" @onclick="HandleNext" disabled="@IsValidating">
        @if (IsValidating)
        {
            <span class="spinner-border spinner-border-sm me-1"></span>
            <span>Validating…</span>
        }
        else
        {
            <span>Next &raquo;</span>
        }
    </button>
</div>

@code {
    [Parameter] public string FullName { get; set; } = "";
    [Parameter] public EventCallback<string> FullNameChanged { get; set; }
    [Parameter] public string Email { get; set; } = "";
    [Parameter] public EventCallback<string> EmailChanged { get; set; }
    [Parameter] public string Phone { get; set; } = "";
    [Parameter] public EventCallback<string> PhoneChanged { get; set; }
    [Parameter] public string Address { get; set; } = "";
    [Parameter] public EventCallback<string> AddressChanged { get; set; }

    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public Func<string, Task<bool>>? ValidateEmail { get; set; }

    private Dictionary<string, string> Errors { get; set; } = new();
    private bool IsValidating { get; set; }

    private async Task HandleNext()
    {
        Errors.Clear();

        if (string.IsNullOrWhiteSpace(FullName))
            Errors["FullName"] = "Full name is required.";
        if (string.IsNullOrWhiteSpace(Email))
            Errors["Email"] = "Email is required.";
        if (string.IsNullOrWhiteSpace(Phone))
            Errors["Phone"] = "Phone is required.";
        if (string.IsNullOrWhiteSpace(Address))
            Errors["Address"] = "Address is required.";

