@page "/apply"
@using sv_25e76fdbe5fb4daea2443b67cafef294.Components.Pages.ApplySteps
@using sv_25e76fdbe5fb4daea2443b67cafef294.Models
@inject IApplicationService ApplicationService
@rendermode InteractiveServer

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4 text-center">Job Application</h2>

    <StepIndicator CurrentStep="@currentStep" OnNavigateToStep="GoToStep" />

    <div class="mt-4">
        @switch (currentStep)
        {
            case 0:
                <StepPersonalInfo
                    FullName="@fullName" FullNameChanged="v => fullName = v"
                    Email="@email" EmailChanged="v => email = v"
                    Phone="@phone" PhoneChanged="v => phone = v"
                    Address="@address" AddressChanged="v => address = v"
                    ValidateEmail="ApplicationService.ValidateEmailAsync"
                    OnNext="NextStep" />
                break;

            case 1:
                <StepWorkHistory
                    Entries="@workEntries" EntriesChanged="v => workEntries = v"
                    OnNext="NextStep" OnBack="PreviousStep" />
                break;

            case 2:
                <StepReferences
                    References="@references" ReferencesChanged="v => references = v"
                    OnNext="NextStep" OnBack="PreviousStep" />
                break;

            case 3:
                <StepCoverLetter
                    CoverLetter="@coverLetter" CoverLetterChanged="v => coverLetter = v"
                    OnNext="NextStep" OnBack="PreviousStep" />
                break;

            case 4:
                <StepReview
                    FullName="@fullName" Email="@email" Phone="@phone" Address="@address"
                    WorkEntries="@workEntries"
                    References="@references"
                    CoverLetter="@coverLetter"
                    OnEditStep="GoToStep" OnBack="PreviousStep" OnSubmit="SubmitApplication"
                    IsSubmitted="@isSubmitted" ApplicationId="@applicationId"
                    IsSubmitting="@isSubmitting" ErrorMessage="@submitError" />
                break;
        }
    </div>
</div>

@code {
    private int currentStep;

    // Step 1
    private string fullName = "";
    private string email = "";
    private string phone = "";
    private string address = "";

    // Step 2
    private List<StepWorkHistory.WorkEntryModel> workEntries = new() { new() };

    // Step 3
    private List<StepReferences.ReferenceModel> references = new() { new(), new() };

    // Step 4
    private string coverLetter = "";

    // Step 5
    private bool isSubmitted;
    private int applicationId;
    private bool isSubmitting;
    private string? submitError;

    private void NextStep() => currentStep++;
    private void PreviousStep() => currentStep--;
    private void GoToStep(int step) => currentStep = step;

    private async Task SubmitApplication()
    {
        isSubmitting = true;
        submitError = null;

        try
        {
            var workHistory = new WorkHistory(
                workEntries.Select(e => new WorkEntry(
                    e.Company, e.Title, e.StartDate, e.EndDate, e.Description
                )).ToList()
            );

            var refs = references.Select(r => new Reference(
                r.Name, r.Relationship, r.Email, r.Phone
            )).ToList();

            var personal = new PersonalInfo(fullName, email, phone, address);
            var application = new JobApplication(personal, workHistory, refs, coverLetter);

            applicationId = await ApplicationService.SubmitApplicationAsync(application);
            isSubmitted = true;
        }
        catch (Exception ex)
        {
            submitError = $"Submission failed: {ex.Message}. Please try again.";
        }
        finally
        {
            isSubmitting = false;
        }
    }
}

