@namespace sv_25e76fdbe5fb4daea2443b67cafef294.Components.Pages.ApplySteps

<h4 class="mb-3">Work History</h4>

@for (int i = 0; i < Entries.Count; i++)
{
    var index = i;
    var entry = Entries[index];

    <div class="card mb-3">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center mb-2">
                <h6 class="mb-0">Position @(index + 1)</h6>
                @if (Entries.Count > 1)
                {
                    <button class="btn btn-outline-danger btn-sm" @onclick="() => RemoveEntry(index)">Remove</button>
                }
            </div>

            <div class="row mb-2">
                <div class="col-md-6">
                    <label class="form-label">Company Name <span class="text-danger">*</span></label>
                    <input type="text" class="form-control" value="@entry.Company"
                           @onchange="@(e => SetField(index, "Company", e))" />
                </div>
                <div class="col-md-6">
                    <label class="form-label">Job Title <span class="text-danger">*</span></label>
                    <input type="text" class="form-control" value="@entry.Title"
                           @onchange="@(e => SetField(index, "Title", e))" />
                </div>
            </div>

            <div class="row mb-2">
                <div class="col-md-4">
                    <label class="form-label">Start Date <span class="text-danger">*</span></label>
                    <input type="date" class="form-control" value="@entry.StartDate.ToString("yyyy-MM-dd")"
                           @onchange="@(e => SetField(index, "StartDate", e))" />
                </div>
                <div class="col-md-4">
                    <label class="form-label">End Date</label>
                    <input type="date" class="form-control" value="@(entry.EndDate?.ToString("yyyy-MM-dd") ?? "")"
                           disabled="@entry.IsCurrent"
                           @onchange="@(e => SetField(index, "EndDate", e))" />
                </div>
                <div class="col-md-4 d-flex align-items-end mb-1">
                    <div class="form-check">
                        <input type="checkbox" class="form-check-input" id="current-@index" checked="@entry.IsCurrent"
                               @onchange="@(e => SetField(index, "IsCurrent", e))" />
                        <label class="form-check-label" for="current-@index">Currently working here</label>
                    </div>
                </div>
            </div>

            <div class="mb-2">
                <label class="form-label">Description</label>
                <textarea class="form-control" rows="2"
                          @onchange="@(e => SetField(index, "Description", e))">@entry.Description</textarea>
            </div>
        </div>
    </div>
}

@if (!string.IsNullOrEmpty(ErrorMessage))
{
    <div class="alert alert-danger">@ErrorMessage</div>
}

<button class="btn btn-outline-secondary mb-3" @onclick="AddEntry">
    <span class="me-1">+</span> Add Another Position
</button>

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="OnBack">&laquo; Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next &raquo;</button>
</div>

@code {
    [Parameter] public List<WorkEntryModel> Entries { get; set; } = new();
    [Parameter] public EventCallback<List<WorkEntryModel>> EntriesChanged { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? ErrorMessage;

    public record WorkEntryModel
    {
        public string Company { get; set; } = "";
        public string Title { get; set; } = "";
        public DateTime StartDate { get; set; } = DateTime.Today;
        public DateTime? EndDate { get; set; }
        public bool IsCurrent { get; set; }
        public string Description { get; set; } = "";
    }

    private void SetField(int index, string field, ChangeEventArgs e)
    {
        var entry = Entries[index];
        var val = e.Value?.ToString() ?? "";

        switch (field)
        {
            case "Company": entry.Company = val; break;
            case "Title": entry.Title = val; break;
            case "StartDate": entry.StartDate = DateTime.TryParse(val, out var sd) ? sd : entry.StartDate; break;
            case "EndDate": entry.EndDate = DateTime.TryParse(val, out var ed) ? ed : null; break;
            case "IsCurrent":
                var isCurrent = e.Value is bool b ? b : bool.TryParse(val, out var bp) && bp;
                entry.IsCurrent = isCurrent;
                if (isCurrent) entry.EndDate = null;
                break;
            case "Description": entry.Description = val; break;
        }
    }

    private void AddEntry()
    {
        Entries.Add(new WorkEntryModel());
    }

    private void RemoveEntry(int index)
    {
        if (Entries.Count > 1)
        {
            Entries.RemoveAt(index);
        }
    }

    private async Task HandleNext()
    {
        ErrorMessage = null;

        foreach (var entry in Entries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) || string.IsNullOrWhiteSpace(entry.Title))
            {
                ErrorMessage = "Each position must have a company name and job title.";
                return;
            }
        }

        await EntriesChanged.InvokeAsync(Entries);
        await OnNext.InvokeAsync();
